1	export interface Item {
2	  type: string;
3	}
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE = 1.1;
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	function roundUpToWholeG(amount: number): number {
18	  // Round to cents first to avoid float-precision artifacts like 100*1.10 = 110.00000000000001
19	  return Math.ceil(Math.round(amount * 100) / 100);
20	}
21	
22	function premiumFor(item: Item): number {
23	  const basePremium = BASE_PREMIUMS[item.type];
24	  return roundUpToWholeG(basePremium * FIRST_INSURANCE_SURCHARGE);
25	}
26	
27	export function quote(
28	  _customer: { yearsWithMHPCO: number },
29	  items: Item[],
30	  _previousContracts?: number,
31	): number {
32	  const itemsTotal = items.reduce((sum, item) => sum + premiumFor(item), 0);
33	  return itemsTotal + PROCESSING_FEE;
34	}
35	
36	export function claim(): number {
37	  return undefined as unknown as number;
38	}
